package com.seaquake6324.civitas.infrastructure.network;
import static org.junit.jupiter.api.Assertions.assertEquals;import io.netty.buffer.Unpooled;import java.util.UUID;import net.minecraft.core.RegistryAccess;import net.minecraft.network.RegistryFriendlyByteBuf;import org.junit.jupiter.api.Test;
class CitizenInfoPayloadTest{@Test void roundTripsAllServerDerivedFields(){UUID route=UUID.randomUUID();var value=new OpenCitizenInfoPayload(UUID.randomUUID(),"Astrid Berg","HUMAN","FEMALE","YOUNG_ADULT",22,91,1F,20F,.1F,1F,"Baker","LOCKED",60,70,80,50,"valid","available","available","available",true,3,true,77F,72F,java.util.List.of(new OpenCitizenInfoPayload.GuardRouteOption(route,4,6)),42);RegistryFriendlyByteBuf b=new RegistryFriendlyByteBuf(Unpooled.buffer(),RegistryAccess.EMPTY);try{OpenCitizenInfoPayload.STREAM_CODEC.encode(b,value);assertEquals(value,OpenCitizenInfoPayload.STREAM_CODEC.decode(b));b.clear();var guard=new SubmitGuardAssignmentPayload(value.citizenId(),value.citizenRevision(),route,4,com.seaquake6324.civitas.domain.security.GuardShift.DAY,true);SubmitGuardAssignmentPayload.STREAM_CODEC.encode(b,guard);assertEquals(guard,SubmitGuardAssignmentPayload.STREAM_CODEC.decode(b));b.clear();var guardResult=new GuardAssignmentResultPayload(true,"civitas.guard.off_shift");GuardAssignmentResultPayload.STREAM_CODEC.encode(b,guardResult);assertEquals(guardResult,GuardAssignmentResultPayload.STREAM_CODEC.decode(b));b.clear();var submit=new SubmitNpcMarriageProposalPayload(value.citizenId(),value.citizenRevision());SubmitNpcMarriageProposalPayload.STREAM_CODEC.encode(b,submit);assertEquals(submit,SubmitNpcMarriageProposalPayload.STREAM_CODEC.decode(b));b.clear();var reproduction=new SubmitNpcReproductionPayload(value.citizenId(),value.citizenRevision());SubmitNpcReproductionPayload.STREAM_CODEC.encode(b,reproduction);assertEquals(reproduction,SubmitNpcReproductionPayload.STREAM_CODEC.decode(b));b.clear();var result=new MarriageActionResultPayload(true,"civitas.marriage.accepted");MarriageActionResultPayload.STREAM_CODEC.encode(b,result);assertEquals(result,MarriageActionResultPayload.STREAM_CODEC.decode(b));b.clear();UUID target=UUID.randomUUID(),proposal=UUID.randomUUID(),consent=UUID.randomUUID();var openPlayer=new OpenPlayerMarriagePayload(target,"Mira","accept",proposal,3,"accept",consent,2);OpenPlayerMarriagePayload.STREAM_CODEC.encode(b,openPlayer);assertEquals(openPlayer,OpenPlayerMarriagePayload.STREAM_CODEC.decode(b));b.clear();var action=new SubmitPlayerMarriageActionPayload(target,SubmitPlayerMarriageActionPayload.Action.ACCEPT,proposal,3);SubmitPlayerMarriageActionPayload.STREAM_CODEC.encode(b,action);assertEquals(action,SubmitPlayerMarriageActionPayload.STREAM_CODEC.decode(b));}finally{b.release();}}}
